class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.init_board()

    def init_board(self):
        pieces = 'brbrrbrb' * 4
        for i, char in enumerate(pieces):
            if char == 'b':
                self.board[i // 8][i % 8] = Piece('black')
            elif char == 'r':
                self.board[i // 8][i % 8] = Piece('white')

    def display(self):
        for row in self.board:
            print(" ".join([piece.symbol if piece else '.' for piece in row]))

class Piece:
    def __init__(self, color):
        self.color = color
        self.king = False

    @property
    def symbol(self):
        return 'B' if self.color == 'black' and not self.king else \
               'K' if self.color == 'black' and self.king else \
               'R' if self.color == 'white' and not self.king else \
               'Q' if self.color == 'white' and self.king else '.'
```

